//! rtmp-push — the sovereign RTMP publisher. Opens raw TCP to an `rtmp://` URL,
//! runs the publish handshake via `frffmpeg::rtmp` (cargo-tested), then streams
//! FLV tag bodies (`frffmpeg::flv` output, read from stdin) as RTMP audio/video
//! messages. This is the I/O glue that replaces native `ffmpeg -f flv rtmp://…`.
//!
//! Build-verified by `cargo build`; a live push is gated on a real URL (arg or
//! `$RTMP_URL`) so it never runs in CI without a server.

use std::io::{Read, Write};
use std::net::TcpStream;
use std::time::Duration;

use frffmpeg::rtmp;

const CMD_CSID: u8 = 3;
const CMD_MSG_TYPE: u8 = 0x14; // AMF0 command message
const CHUNK: usize = 4096;
const STREAM_ID: u32 = 1; // the stream id createStream conventionally returns

struct RtmpUrl {
    host: String,
    port: u16,
    app: String,
    key: String,
    tc_url: String,
}

fn parse_rtmp_url(u: &str) -> Result<RtmpUrl, String> {
    let rest = u.strip_prefix("rtmp://").ok_or("not an rtmp:// url")?;
    let (authority, path) = rest.split_once('/').ok_or("missing /app/streamkey")?;
    let (host, port) = match authority.split_once(':') {
        Some((h, p)) => (h.to_string(), p.parse().map_err(|_| "bad port")?),
        None => (authority.to_string(), 1935u16),
    };
    let (app, key) = path.split_once('/').unwrap_or((path, ""));
    Ok(RtmpUrl {
        host,
        port,
        app: app.to_string(),
        key: key.to_string(),
        tc_url: format!("rtmp://{authority}/{app}"),
    })
}

/// Best-effort: consume server control / `_result` bytes so the socket buffer
/// doesn't stall. (A fully robust client parses Window-Ack/_result/onStatus.)
fn drain(s: &mut TcpStream) {
    let mut buf = [0u8; 4096];
    let _ = s.read(&mut buf);
}

/// Connect + handshake + connect/createStream/publish. Returns the live socket.
fn rtmp_publish(u: &RtmpUrl) -> Result<TcpStream, String> {
    let mut s = TcpStream::connect((u.host.as_str(), u.port)).map_err(|e| format!("connect: {e}"))?;
    s.set_read_timeout(Some(Duration::from_secs(5))).ok();
    s.set_write_timeout(Some(Duration::from_secs(5))).ok();

    // Handshake: C0+C1 → S0+S1+S2 → C2 (echo S1).
    s.write_all(&rtmp::handshake_c0c1(0)).map_err(|e| format!("send C0C1: {e}"))?;
    let mut s0s1s2 = [0u8; 1 + 1536 + 1536];
    s.read_exact(&mut s0s1s2).map_err(|e| format!("read S0S1S2: {e}"))?;
    s.write_all(&rtmp::handshake_c2(&s0s1s2[1..1 + 1536])).map_err(|e| format!("send C2: {e}"))?;

    // connect — MUST be framed at the 128-byte default: it precedes our Set Chunk
    // Size, so a strict server still parses at 128 here (later messages use CHUNK).
    let connect = rtmp::amf0_connect(&u.app, &u.tc_url);
    s.write_all(&rtmp::chunk_message(CMD_CSID, 0, CMD_MSG_TYPE, 0, &connect, 128))
        .map_err(|e| format!("connect: {e}"))?;
    drain(&mut s);

    // raise chunk size, then createStream
    s.write_all(&rtmp::set_chunk_size(CHUNK as u32)).ok();
    let cs = rtmp::amf0_create_stream(2.0);
    s.write_all(&rtmp::chunk_message(CMD_CSID, 0, CMD_MSG_TYPE, 0, &cs, CHUNK))
        .map_err(|e| format!("createStream: {e}"))?;
    drain(&mut s);

    // publish
    let publish = rtmp::amf0_publish(3.0, &u.key);
    s.write_all(&rtmp::chunk_message(CMD_CSID, 0, CMD_MSG_TYPE, STREAM_ID, &publish, CHUNK))
        .map_err(|e| format!("publish: {e}"))?;
    drain(&mut s);
    Ok(s)
}

/// Parse a complete FLV byte stream and push each A/V tag as an RTMP message.
fn stream_flv(s: &mut TcpStream, flv: &[u8]) -> usize {
    if flv.len() < 13 || &flv[0..3] != b"FLV" {
        eprintln!("[rtmp-push] stdin is not an FLV stream");
        return 0;
    }
    let mut pos = 9 + 4; // FLV header (9) + PreviousTagSize0 (4)
    let mut count = 0usize;
    while pos + 11 <= flv.len() {
        let tag_type = flv[pos];
        let size = ((flv[pos + 1] as usize) << 16) | ((flv[pos + 2] as usize) << 8) | (flv[pos + 3] as usize);
        let ts = ((flv[pos + 4] as u32) << 16)
            | ((flv[pos + 5] as u32) << 8)
            | (flv[pos + 6] as u32)
            | ((flv[pos + 7] as u32) << 24);
        let body_start = pos + 11;
        if body_start + size > flv.len() {
            break;
        }
        let body = &flv[body_start..body_start + size];
        let msg = match tag_type {
            0x09 => Some(rtmp::video_message(STREAM_ID, ts, body, CHUNK)),
            0x08 => Some(rtmp::audio_message(STREAM_ID, ts, body, CHUNK)),
            _ => None, // skip script/metadata tags
        };
        if let Some(m) = msg {
            if s.write_all(&m).is_err() {
                break;
            }
            count += 1;
        }
        pos = body_start + size + 4; // + trailing PreviousTagSize
    }
    count
}

fn main() {
    let url = std::env::args().nth(1).or_else(|| std::env::var("RTMP_URL").ok());
    let Some(url) = url else {
        eprintln!("usage: rtmp_push <rtmp://host[:port]/app/streamkey>   (or set RTMP_URL)");
        eprintln!("sovereign RTMP publisher — frffmpeg::rtmp + ::flv, no native ffmpeg.");
        eprintln!("pipe an FLV stream on stdin:  cat stream.flv | rtmp_push rtmp://…");
        std::process::exit(2);
    };
    let parsed = match parse_rtmp_url(&url) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("bad url: {e}");
            std::process::exit(2);
        }
    };
    eprintln!(
        "[rtmp-push] connecting {}:{} app={} key={}",
        parsed.host, parsed.port, parsed.app, parsed.key
    );
    match rtmp_publish(&parsed) {
        Ok(mut s) => {
            eprintln!("[rtmp-push] published — streaming FLV tags from stdin");
            let mut flv = Vec::new();
            let _ = std::io::stdin().read_to_end(&mut flv);
            let n = stream_flv(&mut s, &flv);
            eprintln!("[rtmp-push] pushed {n} tags, done");
        }
        Err(e) => {
            eprintln!("[rtmp-push] failed: {e}");
            std::process::exit(1);
        }
    }
}
